mapper.select:
SELECT DISTINCT ON (scene_group_id) id, clip_key AS clipKey, clip_type AS clipType, session_id AS sessionId, scene_group_id AS sceneGroupId, location_id AS locationId, track_key AS trackKey, start_time AS startTime, end_time AS endTime, pre_roll_sec AS preRollSec, post_roll_sec AS postRollSec, video_url AS videoUrl, status, provider_status AS providerStatus, provider_task_id AS providerTaskId, provider_source_url AS providerSourceUrl, provider_error_message AS providerErrorMessage, public_video_url AS publicVideoUrl FROM presence_video_clips WHERE clip_type = 'scene_group' AND scene_group_id IN
#{sceneGroupId}
ORDER BY scene_group_id, id DESC

SELECT id, target_type AS targetType, target_id AS targetId, model_key AS modelKey, model_name AS modelName, status, summary, appearance, behavior, risk_level AS riskLevel, raw_json AS rawJson, error_message AS errorMessage, created_at AS createdAt, updated_at AS updatedAt FROM ai_analysis_results WHERE target_type = #{targetType} AND target_id IN
#{targetId}
ORDER BY updated_at DESC, id DESC

mapper.update:
UPDATE behavior_logs
SET scene_group_id = COALESCE(#{sceneGroupId}, scene_group_id),
    clip_id = #{clipId},
    analysis_status = #{analysisStatus}
WHERE source = 'live'
  AND track_key = #{trackKey}
  AND location_id = #{locationId}
  AND event_time >= (CAST(#{startTime,jdbcType=TIMESTAMP} AS timestamp) - INTERVAL '10 seconds')
  AND event_time <= (CAST(#{endTime,jdbcType=TIMESTAMP} AS timestamp) + INTERVAL '10 seconds')
